int countTrailingZeros(int n) {
  int count = 0;
  while(n > 0) {
    if(n % 2 == 0) {
      count++; // increment the count if n is even
      n = n >> 1;
    } else {
      break; // stop the loop if n is odd
    }
  }
  return count;
}


